     * SAPISID + co cookies, required for clients6 SAPISIDHASH auth.
     */
    var `cookies`: Map<kotlin.String, kotlin.String>, 
    /**
     * PKCS#8-encoded EC P-256 private key used to sign RegisterRefresh.
     * May be empty for pre-v0.18 sessions (refresh disabled then).
     */
    var `refreshKeyPkcs8`: kotlin.ByteArray, 
    /**
     * dest-registration UUID string appended to every outgoing RPC's
     * `destRegistrationIDs`. Empty for pre-v0.61 sessions.
     */
    var `destRegistrationId`: kotlin.String
) {
    
    companion object
}

/**
 * @suppress
 */
public object FfiConverterTypeRustSession: FfiConverterRustBuffer<RustSession> {
    override fun read(buf: ByteBuffer): RustSession {
        return RustSession(
            FfiConverterByteArray.read(buf),
            FfiConverterLong.read(buf),
            FfiConverterByteArray.read(buf),
            FfiConverterByteArray.read(buf),
            FfiConverterByteArray.read(buf),
            FfiConverterByteArray.read(buf),
            FfiConverterMapStringString.read(buf),
            FfiConverterByteArray.read(buf),
            FfiConverterString.read(buf),
        )
    }

    override fun allocationSize(value: RustSession) = (
            FfiConverterByteArray.allocationSize(value.`tachyonAuthToken`) +
            FfiConverterLong.allocationSize(value.`tokenTtlSeconds`) +
            FfiConverterByteArray.allocationSize(value.`aesKey`) +
            FfiConverterByteArray.allocationSize(value.`hmacKey`) +
            FfiConverterByteArray.allocationSize(value.`mobileDeviceProto`) +
            FfiConverterByteArray.allocationSize(value.`browserDeviceProto`) +
            FfiConverterMapStringString.allocationSize(value.`cookies`) +
            FfiConverterByteArray.allocationSize(value.`refreshKeyPkcs8`) +
            FfiConverterString.allocationSize(value.`destRegistrationId`)
    )

    override fun write(value: RustSession, buf: ByteBuffer) {
            FfiConverterByteArray.write(value.`tachyonAuthToken`, buf)
            FfiConverterLong.write(value.`tokenTtlSeconds`, buf)
            FfiConverterByteArray.write(value.`aesKey`, buf)
            FfiConverterByteArray.write(value.`hmacKey`, buf)
            FfiConverterByteArray.write(value.`mobileDeviceProto`, buf)
            FfiConverterByteArray.write(value.`browserDeviceProto`, buf)
            FfiConverterMapStringString.write(value.`cookies`, buf)
            FfiConverterByteArray.write(value.`refreshKeyPkcs8`, buf)
            FfiConverterString.write(value.`destRegistrationId`, buf)
    }
}





/**
 * Top-level error returned across the UniFFI boundary. Internal errors
 * (e.g. `serde_json::Error`, `reqwest::Error`) get wrapped into one of
 * these variants via `From` impls below — Kotlin never sees the inner
 * types directly.
 */
sealed class LibgmException: kotlin.Exception() {
    
    class Network(
        
        val v1: kotlin.String
        ) : LibgmException() {
        override val message
            get() = "v1=${ v1 }"
    }
    
    class Protocol(
        
        val v1: kotlin.String
        ) : LibgmException() {
        override val message
            get() = "v1=${ v1 }"
    }
    
    class Crypto(
        
        val v1: kotlin.String
        ) : LibgmException() {
        override val message
            get() = "v1=${ v1 }"
    }
    
    class Auth(
        
        val v1: kotlin.String
        ) : LibgmException() {
        override val message
            get() = "v1=${ v1 }"
    }
    
    class NotPaired(
        ) : LibgmException() {
        override val message
            get() = ""
    }
    
    class Cancelled(
        ) : LibgmException() {
        override val message
            get() = ""
    }
    
    class Internal(
        
        val v1: kotlin.String
        ) : LibgmException() {
        override val message
            get() = "v1=${ v1 }"
    }
    

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<LibgmException> {
        override fun lift(error_buf: RustBuffer.ByValue): LibgmException = FfiConverterTypeLibgmError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeLibgmError : FfiConverterRustBuffer<LibgmException> {
    override fun read(buf: ByteBuffer): LibgmException {
        

        return when(buf.getInt()) {
            1 -> LibgmException.Network(
                FfiConverterString.read(buf),
                )
            2 -> LibgmException.Protocol(
                FfiConverterString.read(buf),
                )
            3 -> LibgmException.Crypto(
                FfiConverterString.read(buf),
                )
            4 -> LibgmException.Auth(
                FfiConverterString.read(buf),
                )
            5 -> LibgmException.NotPaired()
            6 -> LibgmException.Cancelled()
            7 -> LibgmException.Internal(
                FfiConverterString.read(buf),
                )
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: LibgmException): ULong {
        return when(value) {
            is LibgmException.Network -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.v1)
            )
            is LibgmException.Protocol -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.v1)
            )
            is LibgmException.Crypto -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.v1)
            )
            is LibgmException.Auth -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.v1)
            )
            is LibgmException.NotPaired -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is LibgmException.Cancelled -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is LibgmException.Internal -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.v1)
            )
        }
    }

    override fun write(value: LibgmException, buf: ByteBuffer) {
        when(value) {
            is LibgmException.Network -> {
                buf.putInt(1)
                FfiConverterString.write(value.v1, buf)
                Unit
            }
            is LibgmException.Protocol -> {
                buf.putInt(2)
                FfiConverterString.write(value.v1, buf)
                Unit
            }
            is LibgmException.Crypto -> {
                buf.putInt(3)
                FfiConverterString.write(value.v1, buf)
                Unit
            }
            is LibgmException.Auth -> {
                buf.putInt(4)
                FfiConverterString.write(value.v1, buf)
                Unit
            }
            is LibgmException.NotPaired -> {
                buf.putInt(5)
                Unit
            }
            is LibgmException.Cancelled -> {
                buf.putInt(6)
                Unit
            }
            is LibgmException.Internal -> {
                buf.putInt(7)
                FfiConverterString.write(value.v1, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}




/**
 * @suppress
 */
public object FfiConverterOptionalByteArray: FfiConverterRustBuffer<kotlin.ByteArray?> {
    override fun read(buf: ByteBuffer): kotlin.ByteArray? {
        if (buf.get().toInt() == 0) {
            return null
        }
        return FfiConverterByteArray.read(buf)
    }

    override fun allocationSize(value: kotlin.ByteArray?): ULong {
        if (value == null) {
            return 1UL
        } else {
            return 1UL + FfiConverterByteArray.allocationSize(value)
        }
    }

    override fun write(value: kotlin.ByteArray?, buf: ByteBuffer) {
        if (value == null) {
            buf.put(0)
        } else {
            buf.put(1)
            FfiConverterByteArray.write(value, buf)
        }
    }
}




/**
 * @suppress
 */
public object FfiConverterSequenceByteArray: FfiConverterRustBuffer<List<kotlin.ByteArray>> {
    override fun read(buf: ByteBuffer): List<kotlin.ByteArray> {
        val len = buf.getInt()
        return List<kotlin.ByteArray>(len) {
            FfiConverterByteArray.read(buf)
        }
    }

    override fun allocationSize(value: List<kotlin.ByteArray>): ULong {
        val sizeForLength = 4UL
        val sizeForItems = value.map { FfiConverterByteArray.allocationSize(it) }.sum()
        return sizeForLength + sizeForItems
    }

    override fun write(value: List<kotlin.ByteArray>, buf: ByteBuffer) {
        buf.putInt(value.size)
        value.iterator().forEach {
            FfiConverterByteArray.write(it, buf)
        }
    }
}




/**
 * @suppress
 */
public object FfiConverterMapStringString: FfiConverterRustBuffer<Map<kotlin.String, kotlin.String>> {
    override fun read(buf: ByteBuffer): Map<kotlin.String, kotlin.String> {
        val len = buf.getInt()
        return buildMap<kotlin.String, kotlin.String>(len) {
            repeat(len) {
                val k = FfiConverterString.read(buf)
                val v = FfiConverterString.read(buf)
                this[k] = v
            }
        }
    }

    override fun allocationSize(value: Map<kotlin.String, kotlin.String>): ULong {
        val spaceForMapSize = 4UL
        val spaceForChildren = value.map { (k, v) ->
            FfiConverterString.allocationSize(k) +
            FfiConverterString.allocationSize(v)
        }.sum()
        return spaceForMapSize + spaceForChildren
    }

    override fun write(value: Map<kotlin.String, kotlin.String>, buf: ByteBuffer) {
        buf.putInt(value.size)
        // The parens on `(k, v)` here ensure we're calling the right method,
        // which is important for compatibility with older android devices.
        // Ref https://blog.danlew.net/2017/03/16/kotlin-puzzler-whose-line-is-it-anyways/
        value.forEach { (k, v) ->
            FfiConverterString.write(k, buf)
            FfiConverterString.write(v, buf)
        }
    }
}








