    UniffiLib.INSTANCE.uniffi_textrcs_libgm_fn_func_derive_session_keys(
        FfiConverterByteArray.lower(`nextKey`),FfiConverterInt.lower(`confirmedKeyDerivationVersion`),_status)
}
